mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY A.SORT_NM, A.PAR_EXAM_CTGR_NM, A.EXAM_CTGRNM) AS LINE_NO , A.* FROM ( SELECT A.EXAM_QBNK_CTGRCD , A.ORG_ID , A.UP_EXAM_QBNK_CTGRCD , A.CRS_ID , A.USER_ID , A.EXAM_CTGRNM , A.EXAM_CTGR_EXPLN , A.EXAM_CTGR_LV , A.EXAM_CTGR_SEQ , A.USEYN , A.DELYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , COUNT(A.EXAM_QBNK_CTGRCD) OVER() AS TOTAL_CNT , CASE WHEN A.UP_EXAM_QBNK_CTGRCD IS NULL THEN A.EXAM_CTGRNM ELSE (SELECT EXAM_CTGRNM FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) END AS PAR_EXAM_CTGR_NM , (SELECT EXAM_CTGR_SEQ FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) AS PAR_EXAM_CTGR_ODR , (SELECT CASE WHEN EXAM_CTGR_LV = 1 THEN EXAM_CTGR_SEQ ELSE EXAM_CTGR_LV + EXAM_CTGR_SEQ END FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD ) AS PAR_EXAM_CTGR_LVL , (SELECT CRSNM FROM TB_LMS_CRS WHERE CRS_ID = A.CRS_ID) AS CRSNM , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS USERNM , CASE WHEN UP_EXAM_QBNK_CTGRCD IS NULL THEN EXAM_CTGRNM ELSE (SELECT EXAM_CTGRNM FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) END AS SORT_NM FROM TB_LMS_EXAM_QBANK_CTGR A WHERE A.DELYN = 'N'
AND A.CRS_ID = #{crsNo}
AND A.EXAM_QBNK_CTGRCD = #{examQbankCtgrCd}
AND ( A.UP_EXAM_QBNK_CTGRCD = #{parExamQbankCtgrCd} OR A.EXAM_QBNK_CTGRCD = #{parExamQbankCtgrCd} )
AND A.USER_ID = #{userId}
AND ( LOWER(A.EXAM_CTGRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT CRSNM FROM TB_LMS_CRS WHERE CRS_ID = A.CRS_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.CRS_ID IN (SELECT DISTINCT CRS_ID FROM TB_LMS_SBJCT WHERE DELYN = 'N' AND SBJCT_ID IN (SELECT SBJCT_ID FROM SBJCT_PROF WHERE USER_ID = #{searchKey} AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y'))
AND A.UP_EXAM_QBNK_CTGRCD IS NULL
AND A.UP_EXAM_QBNK_CTGRCD IS NOT NULL
) A

mapper.insert:
		/*
             SQL ID : ExamQbankCtgrDAO.insertQbankCtgr
            	 설  명 : 문제은행 분류코드 등록
         */
    	INSERT INTO TB_LMS_EXAM_QBANK_CTGR (
    		  EXAM_QBNK_CTGRCD
			, ORG_ID
			, UP_EXAM_QBNK_CTGRCD
			, CRS_ID
			, USER_ID
			, EXAM_CTGRNM
			, EXAM_CTGR_EXPLN
			, EXAM_CTGR_LV
			, EXAM_CTGR_SEQ
			, USEYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{examQbankCtgrCd}
    		, #{orgId}
    		, #{parExamQbankCtgrCd}
    		, #{crsNo}
    		, #{userId}
    		, #{examCtgrNm}
    		, #{examCtgrDesc}
    		, #{examCtgrLvl}
    		, #{examCtgrOdr}
    		, #{useYn}
    		, #{rgtrId}
    		, FN_DTTM()
    		, #{mdfrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ExamQbankCtgrDAO.updateQbankCtgr
            	 설  명 : 문제은행 분류코드 수정
         */
         UPDATE TB_LMS_EXAM_QBANK_CTGR SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()
			, EXAM_CTGRNM = #{examCtgrNm}
			, EXAM_CTGR_EXPLN = #{examCtgrDesc}
			, USEYN = #{useYn}
		 WHERE EXAM_QBNK_CTGRCD = #{examQbankCtgrCd}

		/*
             SQL ID : ExamQbankCtgrDAO.updateQbankCtgrOdr
            	 설  명 : 문제은행 분류코드 순서 수정
         */
         UPDATE TB_LMS_EXAM_QBANK_CTGR SET
         	EXAM_CTGR_SEQ = EXAM_CTGR_SEQ - 1
          WHERE DELYN = 'N'
            AND EXAM_CTGR_SEQ  >  #{examCtgrOdr}


          		AND UP_EXAM_QBNK_CTGRCD = #{parExamQbankCtgrCd}


          		AND UP_EXAM_QBNK_CTGRCD IS NULL

mapper.select:
		/*
             SQL ID : ExamQbankCtgrDAO.selectQbankCtgrOdr
             설  명 : 문제은행 특정 분류코드 순서 조회
         */
    	SELECT 
			NVL(MAX(EXAM_CTGR_SEQ), 0) + 1
		FROM TB_LMS_EXAM_QBANK_CTGR
		WHERE UP_EXAM_QBNK_CTGRCD = #{examQbankCtgrCd}
		  AND DELYN = 'N'
		  AND USER_ID = #{userId}
